"""Default/fallback firmware handler for unknown versions"""

import logging

from .v6_34 import FirmwareHandler_6_34

log = logging.getLogger(__name__)


class FirmwareHandlerDefault(FirmwareHandler_6_34):
    """Fallback handler for unknown firmware versions.

    Inherits from FirmwareHandler_6_34 and attempts to use the same
    logic. This may or may not work depending on how much AT&T changed
    in the new firmware version.

    When using this handler, extra verbose logging is enabled.
    """

    def __init__(self):
        super().__init__()
        self.version = "unknown (using 6.34.x logic as fallback)"
        log.warning("Using default firmware handler - untested version!")
        log.warning("This may not work correctly if AT&T changed the interface")
